30	// ── Coroutine status codes ────────────────────────────────────────────────────
31	
32	// C: #define COS_RUN   0
33	// C: #define COS_DEAD  1
34	// C: #define COS_YIELD 2
35	// C: #define COS_NORM  3
36	
37	/// Coroutine is the currently running thread.
38	const COS_RUN: i32 = 0;
39	
40	/// Coroutine has finished execution or encountered an error.
41	const COS_DEAD: i32 = 1;
42	
43	/// Coroutine is suspended — either yielded or not yet started.
44	const COS_YIELD: i32 = 2;
45	
46	/// Coroutine is normal — it resumed another coroutine and is waiting.
47	const COS_NORM: i32 = 3;
48	
49	/// Human-readable status strings indexed by the `COS_*` constants above.
50	/// Pushed onto the Lua stack as byte strings.
51	///
52	/// C: `static const char *const statname[] = {"running","dead","suspended","normal"};`
53	const STAT_NAMES: [&[u8]; 4] = [b"running", b"dead", b"suspended", b"normal"];
54	
55	// ── Registration table ────────────────────────────────────────────────────────
56	
57	/// Registration table for the `coroutine` standard library.
58	///
59	/// C: `static const luaL_Reg co_funcs[]`
60	///
61	/// Each entry is `(name_bytes, function_pointer)`. Phase B resolves
62	/// `lua_CFunction` to the canonical type alias from `lua-types`.
63	pub const CO_FUNCS: &[(&[u8], lua_CFunction)] = &[
64	    (b"create",      co_create),
65	    (b"resume",      co_resume),
66	    (b"running",     co_running),
67	    (b"status",      co_status),
68	    (b"wrap",        co_wrap),
69	    (b"yield",       co_yield),
70	    (b"isyieldable", co_isyieldable),
71	    (b"close",       co_close),
72	];
