76	/// Retrieves the coroutine thread at stack index 1, raising a type error if
77	/// the argument is absent or not a thread.
78	///
79	/// C: `static lua_State *getco(lua_State *L)`
80	fn get_co(state: &mut LuaState) -> Result<GcRef<lua_types::value::LuaThread>, LuaError> {
81	    let co = state.to_thread(1);
82	    if co.is_none() {
83	        let got = state.arg(1);
84	        return Err(LuaError::type_arg_error(1, "thread", &got));
85	    }
86	    Ok(co.expect("checked above"))
87	}
