92	/// C: `static int auxstatus(lua_State *L, lua_State *co)`
93	fn aux_status(_state: &mut LuaState, _co: &GcRef<lua_types::value::LuaThread>) -> i32 {
94	    // TODO(phase-b): needs lua_vm cross-thread access to status, has_frames,
95	    // get_top, is_same_thread. Phase E wires real coroutines.
96	    todo!("phase-b: coroutine aux_status")
