99	/// Transfers `narg` arguments from `state` to `co`, resumes the coroutine,
100	/// then transfers results (or error message) back to `state`.
101	///
102	/// Returns the number of result values (≥ 0) on success, or `-1` on error
103	/// with the error object left on top of `state`'s stack.
104	///
105	/// C: `static int auxresume(lua_State *L, lua_State *co, int narg)`
106	fn aux_resume(state: &mut LuaState, _co: GcRef<lua_types::value::LuaThread>, _narg: i32) -> i32 {
107	    // Phase A–D stub: real cross-thread resume needs corosensei runtime
108	    // support (PORTING.md §2 #6 — Phase E).  Emulate C's `auxresume` error
109	    // path: push a string error object onto the caller's stack and return
110	    // -1.  `co_resume` packages this as `(false, msg)` and `aux_wrap`
111	    // re-raises it as a Lua error, matching C-Lua semantics on a coroutine
112	    // that cannot run.  Phase E will replace this body with the full
113	    // checkstack / xmove / lua_resume / xmove sequence.
114	    let msg_bytes: &[u8] = b"not yet implemented: coroutines (Phase E)";
115	    match state.intern_str(msg_bytes) {
116	        Ok(s) => state.push(LuaValue::Str(s)),
117	        Err(_) => state.push(LuaValue::Nil),
118	    }
119	    -1
120	}
121	
122	// ── Public library functions ──────────────────────────────────────────────────
123	
124	/// `coroutine.resume(co [, val1, ...])` — attempt to resume coroutine `co`.
125	///
126	/// On success pushes `true` followed by all values yielded or returned by `co`.
127	/// On failure pushes `false` followed by the error object.
128	///
129	/// C: `static int luaB_coresume(lua_State *L)`
130	pub fn co_resume(state: &mut LuaState) -> Result<usize, LuaError> {
131	    // C: lua_State *co = getco(L);
132	    let co = get_co(state)?;
133	    // C: r = auxresume(L, co, lua_gettop(L) - 1);
134	    // PORT NOTE: lua_gettop returns the argument count; -1 excludes the coroutine
135	    // itself which sits at index 1.
136	    let narg = state.get_top() - 1;
137	    let r = aux_resume(state, co, narg);
138	    if r < 0 {
139	        // C: lua_pushboolean(L, 0); lua_insert(L, -2); return 2;
140	        state.push(LuaValue::Bool(false));
141	        state.insert(-2);
142	        Ok(2)
143	    } else {
144	        // C: lua_pushboolean(L, 1); lua_insert(L, -(r + 1)); return r + 1;
145	        state.push(LuaValue::Bool(true));
146	        state.insert(-(r + 1));
147	        Ok((r + 1) as usize)
148	    }
149	}
150	
151	/// Closure body installed by `coroutine.wrap`. The wrapped function is
152	/// stored in upvalue slot 1.
153	///
154	/// C: `static int luaB_auxwrap(lua_State *L)`
155	///
156	/// Phase A–D emulation: on the first call, runs the entire wrapped function
157	/// with a yield buffer installed, collects all yield batches (one per
158	/// `coroutine.yield(...)` call) and the function's final return values as
159	/// the last batch, stores them in `GlobalState::wrap_iter_state` keyed by
160	/// this closure's identity, and returns the first batch. Subsequent calls
161	/// dispense one batch per call (matching real coroutine semantics) until the
162	/// final-return batch is returned, at which point the entry is removed.
163	/// Phase E replaces this with the full cross-thread `auxresume` sequence
164	/// once stackful coroutines land.
165	fn aux_wrap(state: &mut LuaState) -> Result<usize, LuaError> {
166	    let ci_func = state.current_call_info().func;
167	    let func_val = state.get_at(ci_func);
168	    let cache_key = match &func_val {
169	        LuaValue::Function(LuaClosure::C(ccl)) => ccl.identity(),
170	        _ => {
171	            return Err(LuaError::runtime(format_args!(
172	                "coroutine.wrap: aux_wrap called on non-C-closure"
173	            )))
174	        }
175	    };
176	    drop(func_val);
177	
178	    enum Dispense {
179	        Batch(Vec<LuaValue>),
180	        Drain(Option<LuaError>),
181	    }
182	
183	    let maybe_next: Option<Dispense> = {
184	        let mut g = state.global_mut();
185	        g.wrap_iter_state.get_mut(&cache_key).map(|(batches, idx, pending_err)| {
186	            if *idx < batches.len() {
187	                let batch = batches[*idx].clone();
188	                *idx += 1;
189	                Dispense::Batch(batch)
190	            } else {
191	                Dispense::Drain(pending_err.take())
192	            }
193	        })
194	    };
195	
196	    match maybe_next {
197	        Some(Dispense::Batch(batch)) => {
198	            let n = batch.len();
199	            for v in batch {
200	                state.push(v);
201	            }
202	            return Ok(n);
203	        }
204	        Some(Dispense::Drain(pending_err)) => {
205	            state.global_mut().wrap_iter_state.remove(&cache_key);
206	            if let Some(err) = pending_err {
207	                return Err(err);
208	            }
209	            return Ok(0);
210	        }
211	        None => {}
212	    }
213	
214	    // First call: run the wrapped function with a yield buffer active.
215	    let nargs = state.get_top();
216	    let func = state.value_at(upvalue_index(1));
217	    state.push(func);
218	    if nargs > 0 {
219	        state.insert(1)?;
220	    }
221	    state.push_yield_buffer();
222	    // Use LUA_MULTRET (-1) so the function's final return values reach the stack.
223	    let call_result = state.call(nargs, -1);
224	
225	    // If the call succeeded, capture its final return values as the closing
226	    // batch.  On error we discard whatever residue is on the stack and defer
227	    // the error to fire after all already-buffered yield batches have been
228	    // dispensed (matches C-Lua: yields happen before the error surfaces).
229	    let (mut batches, pending_err) = match call_result {
230	        Ok(_) => {
231	            let nret = state.get_top() as i32;
232	            let final_batch: Vec<LuaValue> =
233	                (1..=nret).map(|i| state.value_at(i)).collect();
234	            let mut batches = state.pop_yield_buffer();
235	            batches.push(final_batch);
236	            (batches, None)
237	        }
238	        Err(e) => {
239	            let batches = state.pop_yield_buffer();
240	            (batches, Some(e))
241	        }
242	    };
243	
244	    // Clear residual stack values; we'll push the first batch instead.
245	    lua_vm::api::set_top(state, 0)?;
246	
247	    if batches.is_empty() {
248	        if let Some(err) = pending_err {
249	            return Err(err);
250	        }
251	        return Ok(0);
252	    }
253	
254	    // Remove and return the first batch; save the rest plus any pending
255	    // error for subsequent calls.
256	    let first = batches.remove(0);
257	    let first_n = first.len();
258	
259	    if !batches.is_empty() || pending_err.is_some() {
260	        state
261	            .global_mut()
262	            .wrap_iter_state
263	            .insert(cache_key, (batches, 0, pending_err));
264	    }
265	
266	    for v in first {
267	        state.push(v);
268	    }
269	    Ok(first_n)
270	}
