272	/// `coroutine.create(f)` — create a new coroutine that will run function `f`.
273	///
274	/// Pushes the new thread value and returns 1.
275	///
276	/// C: `static int luaB_cocreate(lua_State *L)`
277	pub fn co_create(state: &mut LuaState) -> Result<usize, LuaError> {
278	    // C: luaL_checktype(L, 1, LUA_TFUNCTION);
279	    state.check_arg_type(1, LuaType::Function)?;
280	    // C: NL = lua_newthread(L);
281	    // TODO(port): coroutine stub — new_thread allocates a fresh LuaState coroutine
282	    // and pushes a Thread value for it; Phase E needed.
283	    let _nl = state.new_thread()?;
284	    // C: lua_pushvalue(L, 1);          /* move function to top */
285	    // C: lua_xmove(L, NL, 1);          /* move function from L to NL */
286	    // PORT NOTE: in C the function copy is pushed and then xmove pops it
287	    // off L's stack into NL's. The Phase E xmove is not yet wired, but the
288	    // net stack effect on L is "thread on top". Skip the push entirely so
289	    // co_wrap's push_cclosure captures the thread (not the function) as
290	    // upvalue 1. Phase E will restore the push + xmove pair.
291	    // TODO(port): coroutine stub — xmove transfers the function from L's stack to
292	    // NL's stack so it becomes the coroutine body; Phase E needed.
293	    Ok(1)
294	}
