296	/// `coroutine.wrap(f)` — create a coroutine and return a resuming function.
297	///
298	/// The returned function, when called, resumes the coroutine as if by
299	/// `coroutine.resume`, but raises an error rather than returning `false`.
300	///
301	/// C: `static int luaB_cowrap(lua_State *L)`
302	///
303	/// Phase A–D emulation: captures `f` as upvalue 1 of `aux_wrap`. Each
304	/// call to the returned function forwards directly to `f` with the same
305	/// args. Phase E will replace this with the real `luaB_cocreate` +
306	/// `auxresume` sequence once stackful coroutines land.
307	pub fn co_wrap(state: &mut LuaState) -> Result<usize, LuaError> {
308	    state.check_arg_type(1, LuaType::Function)?;
309	    state.push_value_at(1)?;
310	    state.push_cclosure(aux_wrap, 1)?;
311	    Ok(1)
312	}
