314	/// `coroutine.yield([...])` — suspend the running coroutine.
315	///
316	/// All arguments are passed back as results of the corresponding `resume`.
317	///
318	/// C: `static int luaB_yield(lua_State *L)`
319	/// → `return lua_yield(L, lua_gettop(L));`
320	/// → `lua_yield(L,n)` is `lua_yieldk(L, n, 0, NULL)` (lua.h:316)
321	///
322	/// Phase A–D buffering-emulation hook: if `aux_wrap` has installed a yield
323	/// buffer on the LuaState (signalling that a `coroutine.wrap` body is
324	/// running synchronously on the main thread), append the arguments into
325	/// that buffer and return 0 values without suspending. The wrapped
326	/// function continues to run; `aux_wrap` dispenses the buffered values one
327	/// per call. If no buffer is active we fall through to the faithful
328	/// `lua_yieldk` translation, which on the main thread surfaces the C-Lua
329	/// "attempt to yield from outside a coroutine" error.
330	pub fn co_yield(state: &mut LuaState) -> Result<usize, LuaError> {
331	    if state.has_yield_buffer() {
332	        let n = state.get_top();
